var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"급한 고비는 넘기셨대. 지금 막 안정을 되찾으셨어.","JPN":"ひとまず峠は越したって。ようやく容体が安定したみたい。","ENG":"He made it past the worst. You should be able to see him now.","TWN":"他們說爺爺已經渡過危險期，目前情況已經穩定下來。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"다행입니다.","JPN":"安心しました。","ENG":"Thank goodness.","TWN":"那就好。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안. 엉겁결에 요양원까지 따라오게 해버렸네.","JPN":"ごめん。結局老人ホームまでついてこさせちゃったね。","ENG":"I’m sorry. I somehow made you follow all the way here.","TWN":"不好意思，突然讓你一起跑來療養院。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 멋대로 쫓아왔을 뿐입니다.","JPN":"私が勝手についてきただけです。","ENG":"No need to be. I am the one who decided to come along.","TWN":"是我自己要跟過來的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그냥 따라온 것 치곤 굉장히 본격적으로 도와주고 있지 않아? 앞치마에 장갑까지……","JPN":"その割には、すごく本格的に手伝ってない？　エプロンに手袋まで……","ENG":"You’re doing way more than tagging along, though... Those gloves and apron...","TWN":"雖然你嘴上說是跟過來的，但你應該是認真要幫忙的吧？看你的圍裙跟手套……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공에겐 신세를 진 게 있으니까요. 마침 공원에서 먼산을 보는 것보다 생산적인 일이 필요했습니다.","JPN":"奈由香殿には借りがありますので。それに私には公園で遠くの山を見ているよりもやりがいのある仕事が必要でした。","ENG":"I owe you a lot, Mr. Nayuka. Also, this is more productive than sitting in the park and doing nothing.","TWN":"因為我欠你人情，而且與其坐在公園發呆，不如做些有建設性的事。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"공원에서 먼산을 보고 있었다고……?","JPN":"公園で遠くの山を……？","ENG":"You were sitting in the park, doing nothing...?","TWN":"你在公園發呆……？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런데 뜻밖입니다. 나유카 공이 요양원에서 일을 돕고 계셨을 줄이야.","JPN":"それより、意外でした。奈由香殿が老人ホームでお仕事を手伝われていたとは。","ENG":"I must say that I am rather surprised. I did not know you were helping with the work here.","TWN":"不過真是意外，沒想到你會在療養院裡幫忙。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하, 할아버지도 자주 볼 겸 요양원비도 벌고 좋잖아?","JPN":"はは、じいちゃんにもよく会えるし、お見舞いをしながら老人ホームの費用も稼げていいでしょ？","ENG":"Ha ha, I get to see my grandfather after all. Plus, they pay me.","TWN":"哈哈，這樣我可以常來看爺爺，還可以順便賺療養院的費用，不是很棒嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"솔직히 그날 이후로…… 할아버지와 떨어져 있는 것도 마음이 놓이지 않아서 말이야.","JPN":"正直あの日以来……じいちゃんと離れているのは不安でさ。","ENG":"To be honest... after what happened that day, I don’t feel comfortable leaving my grandfather alone.","TWN":"老實說，自從那天以後……我也不放心和爺爺分開。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"소중한 사람을 걱정하기에 그 곁을 지킨다는 거군요. 이해했습니다.","JPN":"大切な人が心配だから側で守りたいということですね。納得しました。","ENG":"You worry about your beloved ones, so you want to protect them. I understand.","TWN":"因為擔心重要的人，所以在他身旁守護嗎？我懂。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"NURSE_NPC_HOSPITAL_NULL","text":{"KOREA":"나나하라 씨. 물통 가져왔어.","JPN":"七原さん。バケツ持ってきたよ。","ENG":"Here’s the water you asked for, Miss Nanahara.","TWN":"七原，水桶拿來囉。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"감사합니다. 그럼 왼쪽 복도부터 청소를 시작하겠습니다.","JPN":"ありがとうございます。それでは、左の廊下から掃除します。","ENG":"Thank you. I shall start cleaning the left corridor now.","TWN":"謝謝，那我從左邊的走廊開始打掃。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 오른쪽을 맡을게.","JPN":"僕は右を担当するよ。","ENG":"I’ll take the right, then.","TWN":"那我負責右邊。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"전보다 훨씬 깨끗해졌네. 어르신들도 좋아하겠다. 고생 많았어.","JPN":"前よりずっとキレイになったね。みんなも喜ぶよ。お疲れ様。","ENG":"It looks so much better. The elders would be pleased. Good work.","TWN":"整個煥然一新呢，長輩們應該會很開心吧，辛苦你囉。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그리 힘들진 않았습니다.","JPN":"そこまできつくはありませんでした。","ENG":"It was not hard work.","TWN":"沒有很辛苦。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그리고 이거.","JPN":"あと、これ。","ENG":"Oh, and take this.","TWN":"這給你。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이것은…… 돈입니다만? 왜 저에게 이런 걸 주시는지요?","JPN":"これは……お金？　どうして私にこれを？","ENG":"This is... money. Why are you paying me?","TWN":"這是……錢？為什麼要給我這個？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};